import requests

response = requests.post(
    'https://api.pinelabs.com/v1/transactions',
    headers={
        'Content-Type': 'application/json',
        'Authorization': 'Bearer YOUR_API_KEY'
    },
    json={
        'amount': 10000,
        'currency': 'INR',
        'transaction_type': 'SALE',
        'merchant_id': 'M12345',
        'terminal_id': 'T67890'
    }
)
print(response.json())
